use std::iter;

struct MyIter<T> {
    data: Vec<T>,
}

impl<T> iter::Iterator for MyIter<T>
where T: Copy + Clone + Default
{
    type Item = T;
    fn next(&mut self) -> Option<Self::Item> {
        if self.data.is_empty() {
            None
        } else {
            let item = self.data.remove(0);
            Some(item)
        }
    }
}

